        x3_re = in_re[3*is+k]; x3_im = in_im[3*is+k];
        x4_re = in_re[4*is+k]; x4_im = in_im[4*is+k];

        /* DFT-5 butterfly [bwd] */
        double s1r=(x1_re)+(x4_re), s1i=(x1_im)+(x4_im);
        double d1r=(x1_re)-(x4_re), d1i=(x1_im)-(x4_im);
        double s2r=(x2_re)+(x3_re), s2i=(x2_im)+(x3_im);
        double d2r=(x2_re)-(x3_re), d2i=(x2_im)-(x3_im);
        double ss_r=(s1r)+(s2r), ss_i=(s1i)+(s2i);
